import { Component, OnInit } from '@angular/core';
import { MatDialog } from '@angular/material/dialog';
import { MatSnackBar } from '@angular/material/snack-bar';
import { firstValueFrom } from 'rxjs';
import {
  GridApi, GridReadyEvent, GridOptions, ColDef,
  CellValueChangedEvent, IDetailCellRendererParams
} from 'ag-grid-community';
import { TrackingService } from '../../helpers/services/tracking.service';
import { SAMPLE_TRACKING_COLUMN_HEADERS_CONFIG } from '../../helpers/ag-grid/sample.tracking.config';
import { SamplePhotoRendererComponent, SampleStatusRendererComponent } from './renderers/sample-cell-renderers';
import { EventDialogComponent } from './event-dialog/event-dialog.component';
import { CreateDialogComponent } from './create-dialog/create-dialog.component';
import { DetailDialogComponent } from './detail-dialog/detail-dialog.component';
import { BoxGroupDialogComponent } from './box-group-dialog/box-group-dialog.component';
import { statusLabel } from './helpers/sample.status';

@Component({
  selector: 'app-sample-tracking',
  standalone: false,
  templateUrl: './sample_tracking.component.html',
  styleUrls: ['./sample_tracking.component.scss']
})
export class SampleTrackingComponent implements OnInit {
  gridApi!: GridApi;
  columnDefs: ColDef[] = SAMPLE_TRACKING_COLUMN_HEADERS_CONFIG.columnDefs;
  rowData: any[] = [];
  loading = false;

  gridOptions: GridOptions;

  constructor(
    private trackingService: TrackingService,
    private dialog: MatDialog,
    private snackBar: MatSnackBar
  ) {
    this.gridOptions = {
      rowModelType: 'clientSide',
      masterDetail: true,
      detailRowAutoHeight: true,
      rowSelection: { mode: 'multiRow' } as any,
      defaultColDef: { resizable: true },
      getRowId: (p: any) => String(p.data.sample_id_pk),
      components: {
        samplePhotoRenderer: SamplePhotoRendererComponent,
        sampleStatusRenderer: SampleStatusRendererComponent
      },
      // The detail row shows the sample's event timeline, loaded on expand.
      detailCellRendererParams: {
        detailGridOptions: {
          columnDefs: [
            { headerName: 'When', field: 'event_time', width: 180,
              valueFormatter: (p: any) => p.value ? new Date(p.value).toLocaleString() : '' },
            { headerName: 'Event', field: 'event_type', width: 130 },
            { headerName: 'From', field: 'from_status', width: 160,
              valueFormatter: (p: any) => statusLabel(p.value) },
            { headerName: 'To', field: 'to_status', width: 160,
              valueFormatter: (p: any) => statusLabel(p.value) },
            { headerName: 'Office', field: 'office_location', width: 110 },
            { headerName: 'By', field: 'event_user', width: 140 },
            { headerName: 'Notes', field: 'notes', flex: 1 }
          ],
          defaultColDef: { sortable: true, resizable: true }
        },
        getDetailRowData: (params: any) => {
          this.trackingService.getSampleEvents(params.data.sample_id_pk).subscribe({
            next: (events: any) => params.successCallback(events || []),
            error: () => params.successCallback([])
          });
        }
      } as IDetailCellRendererParams
    };
  }

  ngOnInit(): void {
    // data loads on gridReady
  }

  onGridReady(params: GridReadyEvent): void {
    this.gridApi = params.api;
    this.loadSamples();
  }

  async loadSamples(): Promise<void> {
    this.loading = true;
    try {
      const res: any = await firstValueFrom(
        this.trackingService.getSamples({ startRow: 0, endRow: 1000, filterModel: {} })
      );
      this.rowData = (res && res.rows) ? res.rows : [];
    } catch (e) {
      this.toast('Failed to load samples');
      this.rowData = [];
    } finally {
      this.loading = false;
    }
  }

  private getSelected(): any | null {
    const rows = this.gridApi ? this.gridApi.getSelectedRows() : [];
    return rows && rows.length ? rows[0] : null;
  }

  private getSelectedIds(): number[] {
    const rows = this.gridApi ? this.gridApi.getSelectedRows() : [];
    return (rows || []).map((r: any) => r.sample_id_pk);
  }

  async onOpenDetail(row?: any): Promise<void> {
    const sample = row || this.getSelected();
    if (!sample) { this.toast('Select a sample first'); return; }
    const ref = this.dialog.open(DetailDialogComponent, { width: '760px', data: { ...sample } });
    await firstValueFrom(ref.afterClosed());
    // Photos may have changed -> reload so the grid thumbnail stays in sync.
    await this.loadSamples();
  }

  async onManageBoxes(): Promise<void> {
    const ref = this.dialog.open(BoxGroupDialogComponent, {
      width: '760px',
      data: { selectedSampleIds: this.getSelectedIds() }
    });
    const result = await firstValueFrom(ref.afterClosed());
    if (result && result.changed) await this.loadSamples();
  }

  async onNewSample(): Promise<void> {
    const ref = this.dialog.open(CreateDialogComponent, { width: '520px' });
    const result = await firstValueFrom(ref.afterClosed());
    if (!result) return;
    try {
      await firstValueFrom(this.trackingService.createSample(result));
      this.toast('Sample created');
      await this.loadSamples();
    } catch (e: any) {
      this.toast(this.errMsg(e, 'Failed to create sample'));
    }
  }

  async onRecordEvent(): Promise<void> {
    const row = this.getSelected();
    if (!row) { this.toast('Select a sample first'); return; }
    const ref = this.dialog.open(EventDialogComponent, {
      width: '440px',
      data: {
        sample_id_pk: row.sample_id_pk,
        sample_name: row.sample_name,
        direction: row.direction,
        status: row.status,
        office_location: row.office_location
      }
    });
    const result = await firstValueFrom(ref.afterClosed());
    if (!result) return;
    try {
      await firstValueFrom(this.trackingService.recordSampleEvent(result));
      this.toast('Event recorded');
      await this.loadSamples();
    } catch (e: any) {
      this.toast(this.errMsg(e, 'Could not record event'));
    }
  }

  async onDelete(): Promise<void> {
    const row = this.getSelected();
    if (!row) { this.toast('Select a sample first'); return; }
    if (!confirm(`Delete sample "${row.sample_name || row.sample_id_pk}"? This also removes its photos, comments and history.`)) return;
    try {
      await firstValueFrom(this.trackingService.deleteSample(row.sample_id_pk));
      this.toast('Sample deleted');
      await this.loadSamples();
    } catch (e: any) {
      this.toast(this.errMsg(e, 'Failed to delete sample'));
    }
  }

  async onCellValueChanged(event: CellValueChangedEvent): Promise<void> {
    const field = event.colDef.field;
    if (!field) return;
    const id = event.data.sample_id_pk;
    try {
      await firstValueFrom(this.trackingService.updateSample(id, { [field]: event.newValue }));
    } catch (e: any) {
      this.toast(this.errMsg(e, 'Update failed'));
      await this.loadSamples(); // revert to server truth
    }
  }

  refresh(): void { this.loadSamples(); }

  private errMsg(e: any, fallback: string): string {
    return (e && e.error && e.error.message) ? e.error.message : fallback;
  }
  private toast(msg: string): void {
    this.snackBar.open(msg, 'Dismiss', { duration: 4000 });
  }
}

