    // Remove membership + cache; never delete the samples themselves.
    await sql.sample_shipment_item.destroy({ where: { box_id_fk: id } });
    await sql.sample.update({ box_id_fk: null }, { where: { box_id_fk: id } });
    const deleted = await sql.sample_box.destroy({ where: { box_id_pk: id } });
    if (!deleted) return result({ status: 404, message: 'Box not found' });
    return result(null, { box_id: id, deleted: true });
  } catch (err) {
    console.error('Box.remove error', err);
    return result(err);
  }
};

/**
 * Add samples to a box. A box can bundle samples from multiple factory groups.
 * Direction must match (a sample cannot ride a box going the other way) — such
 * samples are SKIPPED and reported, never blocking the rest (warn, don't block).
 * Box status is independent: this does NOT change any sample's status.
 */
Box.addSamples = async (req, result) => {
  try {
    const user = await getUserInfo(req.headers.authorization);
    const boxId = Number(req.params.id || req.body.box_id_fk);
    const sampleIds = Array.isArray(req.body.sample_ids) ? req.body.sample_ids.map(Number) : [];
    const legType = req.body.leg_type ?? null;

    if (!boxId) return result({ status: 400, message: 'box id is required' });
    if (!sampleIds.length) return result({ status: 400, message: 'sample_ids[] is required' });

    const box = await sql.sample_box.findByPk(boxId);
    if (!box) return result({ status: 404, message: 'Box not found' });

    const samples = await sql.sample.findAll({ where: { sample_id_pk: { [Sequelize.Op.in]: sampleIds } } });
    const found = new Map(samples.map(s => [s.sample_id_pk, s]));

    const added = [];
    const skipped = [];
    for (const id of sampleIds) {
      const s = found.get(id);
      if (!s) { skipped.push({ sample_id: id, reason: 'not found' }); continue; }
      if (box.direction && s.direction && box.direction !== s.direction) {
        skipped.push({ sample_id: id, reason: `direction mismatch (sample ${s.direction} vs box ${box.direction})` });
        continue;
      }
      await sql.sample_shipment_item.create({
        sample_id_fk: id,
        box_id_fk: boxId,
        factory_group_id_fk: s.factory_group_id_fk ?? null,
        leg_type: legType,
        added_date: new Date(),
        added_user: user?.name ?? null
      });
      await sql.sample.update({ box_id_fk: boxId }, { where: { sample_id_pk: id } });
      added.push(id);
    }
    return result(null, { box_id: boxId, added, skipped });
  } catch (err) {
    console.error('Box.addSamples error', err);
    return result(err);
  }
};

Box.removeSamples = async (req, result) => {
  try {
    const boxId = Number(req.params.id || req.body.box_id_fk);
    const sampleIds = Array.isArray(req.body.sample_ids) ? req.body.sample_ids.map(Number) : [];
    if (!boxId) return result({ status: 400, message: 'box id is required' });
    if (!sampleIds.length) return result({ status: 400, message: 'sample_ids[] is required' });

    await sql.sample_shipment_item.destroy({
      where: { box_id_fk: boxId, sample_id_fk: { [Sequelize.Op.in]: sampleIds } }
    });
    await sql.sample.update(
      { box_id_fk: null },
      { where: { box_id_fk: boxId, sample_id_pk: { [Sequelize.Op.in]: sampleIds } } }
    );
    return result(null, { box_id: boxId, removed: sampleIds });
  } catch (err) {
    console.error('Box.removeSamples error', err);
    return result(err);
  }
};

module.exports = { Group, Box };

