const sql = require('../../models/db');
const { getUserInfo } = require('../../helpers/auth');
const Sample = require('../../models/sample.model');

// Invoke a callback-style model method and resolve with { err, data }.
function run(method, req) {
  return new Promise((resolve) => {
    method(req, (err, data) => resolve({ err, data }));
  });
}

const auth = { headers: { authorization: 'token' } };

describe('Sample.create', () => {
  it('defaults direction/status from origin and writes an initial event', async () => {
